sql_examples.sql:
SELECT con_id, name, open_mode, restricted, total_size
FROM V$PDBS
WHERE name = 'PDB$SEED';

CREATE PLUGGABLE DATABASE pdb2
  ADMIN USER pdb2admin IDENTIFIED BY Oracle123
  CREATE_FILE_DEST = '/u01/app/oracle/oradata/CDB1/pdb2/';

-- 1. Application Container (Application Root) 생성
CREATE PLUGGABLE DATABASE app_root AS APPLICATION CONTAINER
  ADMIN USER appadmin IDENTIFIED BY Oracle123
  FILE_NAME_CONVERT = (
    '/u01/oradata/CDB1/pdbseed/',
    '/u01/oradata/CDB1/app_root/'
  );

-- 2. Application Root 열기
ALTER PLUGGABLE DATABASE app_root OPEN;

-- 3. Application Root에 접속
ALTER SESSION SET CONTAINER = app_root;

-- 4. Application Seed 생성
CREATE PLUGGABLE DATABASE AS SEED
  ADMIN USER seedadmin IDENTIFIED BY Oracle123
  FILE_NAME_CONVERT = (
    '/u01/oradata/CDB1/app_root/',
    '/u01/oradata/CDB1/app_seed/'
  );

-- Application Root에 접속
ALTER SESSION SET CONTAINER = app_root;

-- Application PDB 생성 (Application Seed가 자동 템플릿)
CREATE PLUGGABLE DATABASE app_pdb1
  ADMIN USER apppdb1admin IDENTIFIED BY Oracle123
  FILE_NAME_CONVERT = (
    '/u01/oradata/CDB1/app_seed/',
    '/u01/oradata/CDB1/app_pdb1/'
  );

-- Application PDB 열기
ALTER PLUGGABLE DATABASE app_pdb1 OPEN;

-- PDB 열기
ALTER PLUGGABLE DATABASE pdb1 OPEN;

-- 상태 확인 (STATUS가 NEW → NORMAL로 변경)
SELECT pdb_name, status, con_id, creation_scn
FROM DBA_PDBS
ORDER BY con_id;

-- 실시간 상태 확인
SELECT name, open_mode, restricted
FROM V$PDBS
ORDER BY con_id;

-- PDB 저장 상태 설정 (CDB 재시작 시 자동 OPEN)
ALTER PLUGGABLE DATABASE pdb1 SAVE STATE;

-- 저장 상태 확인
SELECT con_name, instance_name, state
FROM DBA_PDB_SAVED_STATES;

-- 저장 상태 해제
ALTER PLUGGABLE DATABASE pdb1 DISCARD STATE;

-- 소스 PDB를 READ ONLY로 변경 (Full Clone 시)
ALTER PLUGGABLE DATABASE pdb_source CLOSE IMMEDIATE;
ALTER PLUGGABLE DATABASE pdb_source OPEN READ ONLY;

-- PDB 클론 실행
CREATE PLUGGABLE DATABASE pdb_clone FROM pdb_source
  FILE_NAME_CONVERT = (
    '/u01/oradata/CDB1/pdb_source/',
    '/u01/oradata/CDB1/pdb_clone/'
  );

-- 클론된 PDB 열기
ALTER PLUGGABLE DATABASE pdb_clone OPEN;

-- 소스 PDB를 다시 READ WRITE로 변경
ALTER PLUGGABLE DATABASE pdb_source CLOSE IMMEDIATE;
ALTER PLUGGABLE DATABASE pdb_source OPEN READ WRITE;

-- PDB Unplug
ALTER PLUGGABLE DATABASE pdb1 CLOSE IMMEDIATE;
ALTER PLUGGABLE DATABASE pdb1 UNPLUG INTO '/tmp/pdb1.xml';
DROP PLUGGABLE DATABASE pdb1 KEEP DATAFILES;

-- 대상 CDB에서 호환성 검사
SET SERVEROUTPUT ON
DECLARE
  compatible BOOLEAN;
BEGIN
  compatible := DBMS_PDB.CHECK_PLUG_COMPATIBILITY(
    pdb_descr_file => '/tmp/pdb1.xml');
  IF compatible THEN
    DBMS_OUTPUT.PUT_LINE('Compatible: YES');
  ELSE
    DBMS_OUTPUT.PUT_LINE('Compatible: NO');
  END IF;
END;
/

-- 호환성 위반 사항 확인
SELECT name, cause, type, message
FROM PDB_PLUG_IN_VIOLATIONS
WHERE status = 'PENDING'
ORDER BY name;
